import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart, ResponsiveChartContainer, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface SleepStage {
  name: string;
  value: number;
}

interface SleepData {
  lastNight: {
    duration: string;
    sleepScore: number;
  };
  sleepStages: SleepStage[];
  weeklyAverage: {
    duration: string;
    sleepScore: number;
  };
}

export default function Widget() {
  const sleepData = response.data as SleepData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Sleep Quality
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#F59E0B' }}>
              {sleepData.lastNight.sleepScore} / 100
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Last Night: {sleepData.lastNight.duration}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'pie',
                  data: sleepData.sleepStages.map(stage => ({ id: stage.name, value: stage.value })),
                  color: ['#3B82F6', '#F59E0B', '#10B981', '#EF4444'],
                },
              ]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <PieChart />
              </g>
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Weekly Average
            </Typography>
            <Typography variant="body1" sx={{ color: '#F59E0B' }}>
              {sleepData.weeklyAverage.duration}, Score: {sleepData.weeklyAverage.sleepScore}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
